export { Drag } from "./Options/Classes/Drag.js";
export async function loadExternalDragInteraction(engine) {
    engine.checkVersion("4.1.1");
    await engine.pluginManager.register(async (e) => {
        const { ensureInteractivityPluginLoaded } = await import("@tsparticles/plugin-interactivity/lazy");
        ensureInteractivityPluginLoaded(e);
        e.pluginManager.addInteractor?.("externalDrag", async (container) => {
            const { Dragger } = await import("./Dragger.js");
            return new Dragger(container);
        });
    });
}
